	// NOTE: if we can move icons to an attachment on the ui action, we could reduce this to filtering out separators and pull all list context menu actions
	_load_context_menu: function(gr_recordObject){
		var lContextMenuInformation = {};
		var arrMenuItems = [];
		var ui_action_menu_item = {};
		var objectType = "";
		var apiObject;
		var form;
		var ui_actions;
		var taskId = gr_recordObject.getUniqueValue();
		var tableName = gr_recordObject.getRecordClassName();
		if(tableName == api_dtech_common.CONST_DTECH_TASK_TABLE_NAME){
			objectType = "task";
			form = $sp.getForm(tableName, taskId);
			ui_actions = form._ui_actions;
			lContextMenuInformation.taskId = taskId;
			apiObject = new api_tasker_task();			
		} else if(tableName == api_dtech_common.CONST_DTECH_TEMPLATE_TASK_TABLE_NAME){
			objectType = "templateTask";
			form = $sp.getForm(tableName, taskId);
			ui_actions = form._ui_actions;
			lContextMenuInformation.taskId = taskId;
			apiObject = new api_tasker_template();
		} else {
			gs.info("Tasker Error - loading context menu actions for table: " + tableName + " Not implemented for Template yet");
		}
		lContextMenuInformation.objectType = objectType;
		// use the api object above and load the context menu actions
		var arrHCMUI = apiObject._get_ui_actions_context_menu_array();
		// use the api object above and load the action icons
		var ui_actions_icons = apiObject._get_ui_actions_icons();
		var orderCount = 0;
		for (actionIndex=0; actionIndex < arrHCMUI.length; actionIndex++) {
			var addAction = false;
			var hcm_item = arrHCMUI[actionIndex];
			if(hcm_item != "separator"){
				var arrItem = ui_actions.filter(function(item){
					return item.sys_id==hcm_item;});
				// if the action was not returned, then the user doesn't have permsissions, don't add it
				if(arrItem[0]){
					addAction=true;
					ui_action_menu_item = arrItem[0];
					ui_action_menu_item.order = actionIndex;
					ui_action_menu_item.image = undefined;
					var ui_action_icon = ui_actions_icons[ui_action_menu_item.sys_id];
					if(ui_action_icon){
						ui_action_menu_item.image = ui_action_icon.image;
					}
					var params = {};
					// use the api object above and load the action parameters
					params = apiObject._get_ui_actions_params(gr_recordObject, ui_action_menu_item.sys_id);
					ui_action_menu_item.params = params;
				}
			} else {
				addAction=true;
				ui_action_menu_item = {
					"sys_id" : "separtor" + actionIndex.toString(),
					"name": "separator",
					"order": actionIndex
				};
			}
			if(addAction){
				arrMenuItems.push(ui_action_menu_item);				
			}
		}

		// now filter out adjacent separators
		var prevIsSeparator = false;  // defined outside the function so it keeps a flag if the previous item is a spearator
		arrMenuItems = arrMenuItems.filter(function(item){
			var include=true;
			if(prevIsSeparator && item.name=="separator"){
				// this item and previous are both separators.  Skip and do not include
				include = false;
			}
			prevIsSeparator = item.name=="separator";
			return include;
		});
		// remove leading separators
		while(arrMenuItems.length>0 && arrMenuItems[0].name=="separator"){
			arrMenuItems.shift();
		}
		while(arrMenuItems.length>0 && arrMenuItems[arrMenuItems.length-1].name=="separator"){
			arrMenuItems.pop();
		}
		lContextMenuInformation.ui_actions = arrMenuItems;
		return lContextMenuInformation;
	},


	// ************************************************************************
	// Internal methods below 
	// ************************************************************************
	_getSubTaskList: function(gr_recordObject){
		var objectType = "";
		var lSubTaskInfo = {};
		var lSubTasks = [];
		var arrSubTaskListFields = [];
		var gr_subtasks;
// TODO - See Template fieldname differences and update Macro, Script in the macro and controller
		var tableName = gr_recordObject.getRecordClassName();
		if(tableName == api_dtech_common.CONST_DTECH_TASK_TABLE_NAME){
			arrSubTaskListFields = 
				["short_description", "state", "number", "task_order"];
			gr_subtasks = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TASK_TABLE_NAME);
		} else if(tableName == api_dtech_common.CONST_DTECH_TEMPLATE_TASK_TABLE_NAME){
// TODO - See Template fieldname differences and update Macro, Script in the macro and controller
//  task_order -> route_order
//  state -> NOT ON THIS TABLE
// NOTE: there are other fields used here, need to look to see what we need for warnings
			title = gr_recordObject.getDisplayValue(api_dtech_common.CONST_DTECH_TEMPLATE_TASK_TITLE_FIELD);
			arrSubTaskListFields = 
				["short_description", "number", "route_order"];
			gr_subtasks = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TEMPLATE_TASK_TABLE_NAME);
		}

		gr_subtasks.addQuery("parent", gr_recordObject.getUniqueValue());
		gr_subtasks.query();
		while(gr_subtasks.next()){
			lSubTaskInfo = this.api_dtech.loadObject(gr_subtasks, arrSubTaskListFields);
			// add task id after loaded
			lSubTaskInfo.taskId = gr_subtasks.getUniqueValue();
			lSubTasks.push(lSubTaskInfo);
		}
		return lSubTasks;
	},

	_getReferenceFields: function(tableName, referenceId, arrReferenceFields){
		var lReferenceInfo;
		var gr_reference = new GlideRecordSecure(tableName);
		if(gr_reference.get(referenceId)){
			lReferenceInfo = this.api_dtech.loadObject(gr_reference, arrReferenceFields);
		}
		return lReferenceInfo;
	},

	_loadPhotosForObjects: function(infoObject, fields){
		var arrMembers = [];
		var userInfo = new UserInfoScripts();
		for (i=0; i < fields.length; i++) {
			var fieldName = fields[i];
			var field = infoObject[fieldName];
			field.order = i;
			if(field.value && field.value!=null && field.value!="null"){
				field.photoInfo = userInfo.loadPhotoInfo(field.value, true);
			}
			arrMembers.push(field);
		}
		return arrMembers;
	},

    type: 'api_tasker_ui_component_data'
